namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories = new List<RecipeCategory>
        {
            new() { Name = "Breakfast", Description = "Start your day right", Icon = "🥞" },
            new() { Name = "Lunch", Description = "Midday meals and light bites", Icon = "🥗" },
            new() { Name = "Dinner", Description = "Hearty evening dishes", Icon = "🍝" },
            new() { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
            new() { Name = "Snacks", Description = "Quick bites between meals", Icon = "🍿" },
            new() { Name = "Drinks", Description = "Refreshing beverages", Icon = "🍹" }
        };

        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt\nButter for cooking",
                Steps = "1. Mix dry ingredients in a bowl.\n2. Whisk eggs and milk together.\n3. Combine wet and dry ingredients until just mixed.\n4. Heat a buttered pan over medium heat.\n5. Pour 1/4 cup batter per pancake.\n6. Flip when bubbles form on surface.\n7. Cook until golden brown.",
                AverageRating = 4.5, RatingCount = 12
            },
            new()
            {
                Id = 2, Title = "Caesar Salad", Category = "Lunch",
                Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan cheese\nCaesar dressing\nBlack pepper",
                Steps = "1. Wash and chop romaine lettuce.\n2. Toss with Caesar dressing.\n3. Top with croutons and shaved parmesan.\n4. Season with freshly ground black pepper.",
                AverageRating = 4.2, RatingCount = 8
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
                Ingredients = "400g spaghetti\n500g ground beef\n1 onion, diced\n3 cloves garlic\n400g crushed tomatoes\n2 tbsp tomato paste\nOlive oil\nSalt, pepper, basil, oregano",
                Steps = "1. Cook spaghetti according to package directions.\n2. Brown ground beef in olive oil, drain excess fat.\n3. Sauté onion and garlic until soft.\n4. Add crushed tomatoes and tomato paste.\n5. Season with salt, pepper, basil, and oregano.\n6. Simmer sauce for 20 minutes.\n7. Serve sauce over spaghetti.",
                AverageRating = 4.8, RatingCount = 24
            },
            new()
            {
                Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = "2.25 cups flour\n1 cup butter, softened\n3/4 cup sugar\n3/4 cup brown sugar\n2 eggs\n1 tsp vanilla\n1 tsp baking soda\n2 cups chocolate chips",
                Steps = "1. Preheat oven to 375°F (190°C).\n2. Cream butter and sugars together.\n3. Beat in eggs and vanilla.\n4. Mix in flour and baking soda.\n5. Fold in chocolate chips.\n6. Drop spoonfuls onto baking sheet.\n7. Bake 9-11 minutes until golden.",
                AverageRating = 4.9, RatingCount = 31
            },
            new()
            {
                Id = 5, Title = "Guacamole", Category = "Snacks",
                Ingredients = "3 ripe avocados\n1 lime, juiced\n1 tsp salt\n1/2 cup diced onion\n3 tbsp fresh cilantro\n2 roma tomatoes, diced\n1 tsp minced garlic\n1 pinch cayenne pepper",
                Steps = "1. Cut avocados in half and remove pit.\n2. Scoop out flesh and mash with a fork.\n3. Stir in lime juice and salt.\n4. Mix in onion, cilantro, tomatoes, and garlic.\n5. Add cayenne pepper to taste.\n6. Serve immediately with tortilla chips.",
                AverageRating = 4.6, RatingCount = 15
            },
            new()
            {
                Id = 6, Title = "Mango Smoothie", Category = "Drinks",
                Ingredients = "1 cup frozen mango chunks\n1 banana\n1 cup yogurt\n1/2 cup orange juice\n1 tbsp honey",
                Steps = "1. Add all ingredients to a blender.\n2. Blend until smooth.\n3. Pour into a glass and serve immediately.",
                AverageRating = 4.3, RatingCount = 9
            }
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        var totalRating = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "hovered" : "") @(star <= _selectedStar ? "selected" : "")"
              @onmouseover="() => OnHover(star)"
              @onmouseout="OnHoverOut"
              @onclick="() => OnClick(star)">
            ★
        </span>
    }
    <span class="rating-info">
        @if (_submitted)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        else
        {
            <span>@AverageRating.ToString("F1") avg (@RatingCount ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _hoveredStar;
    private int _selectedStar;
    private bool _submitted;

    private void OnHover(int star) => _hoveredStar = star;
    private void OnHoverOut() => _hoveredStar = 0;

    private void OnClick(int star)
    {
        _selectedStar = star;
        _submitted = true;
        RecipeService.AddRating(RecipeId, star);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

@page "/recipes/{CategoryName}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Any())
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ★ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipes/detail/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category yet. Be the first to <a href="/submit">submit one</a>!</p>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    private List<Recipe> _recipes = new();

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipes/detail/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@using RecipeShare.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (_recipe is not null)
{
    <h1>@_recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@_recipe.Category</span>

    <div class="mb-4">
        <StarRating RecipeId="@_recipe.Id"
                    AverageRating="@_recipe.AverageRating"
                    RatingCount="@_recipe.RatingCount" />
    </div>

    <div class="row">
        <div class="col-md-5">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var ingredient in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <li class="mb-1">• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-2">@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <a href="/recipes/@_recipe.Category" class="btn btn-outline-secondary">← Back to @_recipe.Category</a>
}
else
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added to the @_model.Category category.</p>
        <a href="/recipes/@_model.Category" class="btn btn-primary">View in Category</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in _categories)
                {
                    <option value="@cat.Name">@cat.Name</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="_model.Ingredients"
                           placeholder="One ingredient per line" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="_model.Steps"
                           placeholder="Describe each step on a new line" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private Recipe _model = new();
    private List<RecipeCategory> _categories = new();
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_model.Title) ||
            string.IsNullOrWhiteSpace(_model.Category) ||
            string.IsNullOrWhiteSpace(_model.Ingredients) ||
            string.IsNullOrWhiteSpace(_model.Steps))
            return;

        RecipeService.AddRecipe(_model);
        _submitted = true;
    }
}

