        };

        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt\nButter for cooking",
                Steps = "1. Mix dry ingredients in a bowl.\n2. Whisk eggs and milk together.\n3. Combine wet and dry ingredients until just mixed.\n4. Heat a buttered pan over medium heat.\n5. Pour 1/4 cup batter per pancake.\n6. Flip when bubbles form on surface.\n7. Cook until golden brown.",
                AverageRating = 4.5, RatingCount = 12
            },
            new()
            {
                Id = 2, Title = "Caesar Salad", Category = "Lunch",
                Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan cheese\nCaesar dressing\nBlack pepper",
                Steps = "1. Wash and chop romaine lettuce.\n2. Toss with Caesar dressing.\n3. Top with croutons and shaved parmesan.\n4. Season with freshly ground black pepper.",
                AverageRating = 4.2, RatingCount = 8
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
                Ingredients = "400g spaghetti\n500g ground beef\n1 onion, diced\n3 cloves garlic\n400g crushed tomatoes\n2 tbsp tomato paste\nOlive oil\nSalt, pepper, basil, oregano",
                Steps = "1. Cook spaghetti according to package directions.\n2. Brown ground beef in olive oil, drain excess fat.\n3. Sauté onion and garlic until soft.\n4. Add crushed tomatoes and tomato paste.\n5. Season with salt, pepper, basil, and oregano.\n6. Simmer sauce for 20 minutes.\n7. Serve sauce over spaghetti.",
                AverageRating = 4.8, RatingCount = 24
            },
            new()
            {
                Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = "2.25 cups flour\n1 cup butter, softened\n3/4 cup sugar\n3/4 cup brown sugar\n2 eggs\n1 tsp vanilla\n1 tsp baking soda\n2 cups chocolate chips",
                Steps = "1. Preheat oven to 375°F (190°C).\n2. Cream butter and sugars together.\n3. Beat in eggs and vanilla.\n4. Mix in flour and baking soda.\n5. Fold in chocolate chips.\n6. Drop spoonfuls onto baking sheet.\n7. Bake 9-11 minutes until golden.",
                AverageRating = 4.9, RatingCount = 31
            },
            new()
            {
                Id = 5, Title = "Guacamole", Category = "Snacks",
                Ingredients = "3 ripe avocados\n1 lime, juiced\n1 tsp salt\n1/2 cup diced onion\n3 tbsp fresh cilantro\n2 roma tomatoes, diced\n1 tsp minced garlic\n1 pinch cayenne pepper",
                Steps = "1. Cut avocados in half and remove pit.\n2. Scoop out flesh and mash with a fork.\n3. Stir in lime juice and salt.\n4. Mix in onion, cilantro, tomatoes, and garlic.\n5. Add cayenne pepper to taste.\n6. Serve immediately with tortilla chips.",
                AverageRating = 4.6, RatingCount = 15
            },
            new()
            {
                Id = 6, Title = "Mango Smoothie", Category = "Drinks",
                Ingredients = "1 cup frozen mango chunks\n1 banana\n1 cup yogurt\n1/2 cup orange juice\n1 tbsp honey",
                Steps = "1. Add all ingredients to a blender.\n2. Blend until smooth.\n3. Pour into a glass and serve immediately.",
                AverageRating = 4.3, RatingCount = 9
            }
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        var totalRating = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
    }
}
"}

{"path": "/tmp/sv-9c22e10a78f743ec8cd88d7e448c437d/RecipeShare/Components/Shared/StarRating.razor", "file_text": "@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "hovered" : "") @(star <= _selectedStar ? "selected" : "")"
              @onmouseover="() => OnHover(star)"
              @onmouseout="OnHoverOut"
              @onclick="() => OnClick(star)">
            ★
        </span>
    }
    <span class="rating-info">
        @if (_submitted)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        else
        {
            <span>@AverageRating.ToString("F1") avg (@RatingCount ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _hoveredStar;
    private int _selectedStar;
    private bool _submitted;

    private void OnHover(int star) => _hoveredStar = star;
    private void OnHoverOut() => _hoveredStar = 0;

    private void OnClick(int star)
    {
        _selectedStar = star;
        _submitted = true;
        RecipeService.AddRating(RecipeId, star);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}
"}

